package Lec3;

public class For_loops_Demo {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		for (int i = 1; i <= 5; i++) {
			System.out.println("Hello");
		}
		for (int i = 1; i <= 5;) {
			System.out.println("Hello");
			i++;
		}
		int i = 1;
		for (; i <= 5;) {
			System.out.println("Hello");
			i++;
		}

	}

}
